class Solution:
    def possibleStringCount(self, word: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(word)
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            dp[i] = dp[i - 1]
            for j in range(i):
                if word[j] == word[i - 1]:
                    dp[i] = (dp[i] + dp[j]) % MOD
        return dp[n] - dp[k - 1] if k <= n else dp[n]

